#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& e : edges) {
        adj[e[0]].push_back({e[1], e[2]});
    }

    // Priority queue for Dijkstra's algorithm
    priority_queue<pair<long long, pair<long long, bool>>, vector<pair<long long, pair<long long, bool>>>, greater<pair<long long, pair<long long, bool>>>> pq;

    // dist[i][0] = cost to reach node i without using the switch
    // dist[i][1] = cost to reach node i with using the switch
    vector<vector<long long>> dist(n, vector<long long>(2, LLONG_MAX));
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long node = pq.top().second.first;
        bool usedSwitch = pq.top().second.second;
        pq.pop();

        if (node == n - 1) {
            return cost;
        }

        if (cost > dist[node][usedSwitch]) {
            continue;
        }

        // Traverse normal edges
        for (auto& [neighbor, weight] : adj[node]) {
            long long newCost = cost + weight;
            if (newCost < dist[neighbor][usedSwitch]) {
                dist[neighbor][usedSwitch] = newCost;
                pq.push({newCost, {neighbor, usedSwitch}});
            }
        }

        // Check if we can flip the switch at this node
        if (!usedSwitch) {
            // Flip the switch (reverse the edge)
            long long newCostFlip = cost + 2 * weight;
            if (newCostFlip < dist[node][1]) {
                dist[node][1] = newCostFlip;
                pq.push({newCostFlip, {node, 1}});
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

